mapper.select:
SELECT p.id, p.title, COALESCE(m.nickname, '탈퇴한 사용자') AS authorNickname, p.view_count AS viewCount, p.like_count AS likeCount, p.created_at AS createdAt, false AS liked FROM post p LEFT JOIN member m ON m.id = p.member_id
ORDER BY p.like_count DESC, p.created_at DESC ORDER BY p.created_at DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE post
SET title = #{title}, content = #{content}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
